syntaxExplanation:
a = {1, 2, 3}
b = {3, 4, 5}
print(a | b)  # Union: {1, 2, 3, 4, 5}
print(a & b)  # Intersection: {3}
print(a - b)  # Difference: {1, 2}

examples.code:
raw_tags = ['python', 'coding', 'python', 'web']
unique_tags = set(raw_tags)
print(unique_tags)  # {'python', 'coding', 'web'}

admin_users = {'alice', 'bob'}
active_users = {'bob', 'charlie'}
print('Active Admins:', admin_users & active_users)  # {'bob'}
